Creating a TypeScript decorator for method memoization with Time-To-Live (TTL) support involves a few steps. The decorator will cache the results of method calls and invalidate the cache after a specified duration. Below is a complete implementation of such a decorator.

### Memoization Decorator with TTL

```typescript
function MemoizeWithTTL(ttl: number) {
    return function (target: any, propertyKey: string, descriptor: PropertyDescriptor) {
        const originalMethod = descriptor.value;
        const cache: Map<string, { value: any; expiry: number }> = new Map();

        descriptor.value = function (...args: any[]) {
            const key = JSON.stringify(args); // Create a unique key based on arguments
            const now = Date.now();

            // Check if the cache has the value and if it is still valid
            if (cache.has(key)) {
                const cached = cache.get(key)!;
                if (now < cached.expiry) {
                    return cached.value; // Return cached value if not expired
                }
                cache.delete(key); // Remove expired cache
            }

            // Call the original method and cache the result
            const result = originalMethod.apply(this, args);
            cache.set(key, { value: result, expiry: now + ttl });
            return result;
        };

        return descriptor;
    };
}

// Example usage
class Example {
    @MemoizeWithTTL(5000) // Cache for 5 seconds
    expensiveCalculation(num: number): number {
        console.log('Calculating...');
        return num * 2; // Simulate an expensive operation
    }
}

// Testing the decorator
const example = new Example();

console.log(example.expensiveCalculation(5)); // Calculating... 10
console.log(example.expensiveCalculation(5)); // 10 (cached result)
setTimeout(() => {
    console.log(example.expensiveCalculation(5)); // Calculating... 10 (cache expired)
}, 6000);
```

